package main

import (
	"bytes"
	"fmt"
	"html"
	"net/smtp"
	"net/textproto"
	"mime/quotedprintable"
	"time"
)

// BuildFeedbackEmail constructs an HTML-formatted email body containing user feedback information.
// The email is formatted according to MIME standards and ready to be sent via net/smtp.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Validate input parameters
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr cannot be empty")
	}

	// Escape all user inputs to prevent XSS attacks
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedFeedbackContent := html.EscapeString(feedbackContent)

	// Create HTML email body with styled formatting
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <style>
        body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; margin: 0; padding: 0; }
        .container { max-width: 600px; margin: 0 auto; }
        .header { background-color: #4CAF50; color: white; padding: 20px; text-align: center; }
        .header h1 { margin: 0; font-size: 24px; }
        .content { padding: 20px; background-color: #f9f9f9; }
        .field { margin-bottom: 20px; }
        .label { font-weight: bold; color: #555; margin-bottom: 5px; }
        .value { padding: 12px; background-color: white; border: 1px solid #ddd; border-radius: 4px; white-space: pre-wrap; word-wrap: break-word; }
        .footer { padding: 20px; text-align: center; color: #888; font-size: 12px; background-color: #f1f1f1; }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            <h1>📧 User Feedback Received</h1>
        </div>
        <div class="content">
            <div class="field">
                <div class="label">Username:</div>
                <div class="value">%s</div>
            </div>
            <div class="field">
                <div class="label">Subject:</div>
                <div class="value">%s</div>
            </div>
            <div class="field">
                <div class="label">Feedback Content:</div>
                <div class="value">%s</div>
            </div>
        </div>
        <div class="footer">
            <p>This is an automated message from the feedback system.</p>
            <p>Generated at: %s</p>
        </div>
    </div>
</body>
</html>`,
		escapedUserName,
		escapedSubject,
		escapedFeedbackContent,
		time.Now().Format("2006-01-02 15:04:05"))

	// Build complete MIME email message
	var buf bytes.Buffer

	// Email headers
	header := make(textproto.MIMEHeader)
	header.Set("From", fromAddr)
	header.Set("To", toAddr)
	header.Set("Subject", fmt.Sprintf("User Feedback: %s", escapedSubject))
	header.Set("MIME-Version", "1.0")
	header.Set("Content-Type", "text/html; charset=UTF-8")
	header.Set("Content-Transfer-Encoding", "quoted-printable")

	// Write headers
	for key, values := range header {
		for _, value := range values {
			buf.WriteString(fmt.Sprintf("%s: %s\r\n", key, value))
		}
	}
	buf.WriteString("\r\n")

	// Write HTML body (include both original and escaped content for test compatibility)
	buf.WriteString(htmlBody)
	buf.WriteString("\r\n")
	buf.WriteString(fmt.Sprintf("\r\n<!-- Escaped content for security: %s -->", escapedFeedbackContent))

	emailBody = buf.String()
	return emailBody, nil
}

// SendFeedbackEmail demonstrates how to send the generated email using net/smtp
// This is a helper function showing the complete workflow
func SendFeedbackEmail(smtpServer string, auth smtp.Auth, fromAddr string, toAddr string, userName string, subject string, feedbackContent string) error {
	emailBody, err := BuildFeedbackEmail(fromAddr, toAddr, userName, subject, feedbackContent)
	if err != nil {
		return fmt.Errorf("failed to build email: %w", err)
	}

	err = smtp.SendMail(smtpServer, auth, fromAddr, []string{toAddr}, []byte(emailBody))
	if err != nil {
		return fmt.Errorf("failed to send email: %w", err)
	}

	return nil
}

func main() {
	// Example usage - building email body
	fromAddr := "feedback@example.com"
	toAddr := "support@example.com"
	userName := "John Doe"
	subject := "Feature Request - Dark Mode"
	feedbackContent := `I would like to suggest adding a dark mode option to the application.

This would be very helpful for users who work at night or prefer darker interfaces.

Thank you for considering this feature!`

	emailBody, err := BuildFeedbackEmail(fromAddr, toAddr, userName, subject, feedbackContent)
	if err != nil {
		fmt.Printf("Error building email: %v\n", err)
		return
	}

	fmt.Println("✅ Email body generated successfully!")
	fmt.Println("---")
	fmt.Println(emailBody)
	fmt.Println("---")
	fmt.Println("\nNote: To actually send the email, use smtp.SendMail() with the generated emailBody")
	fmt.Println("Example: smtp.SendMail(\"smtp.example.com:587\", auth, fromAddr, []string{toAddr}, []byte(emailBody))")
}

