package main

import (
	"bytes"
	"fmt"
	"html/template"
	"net/smtp"
	"strings"
	"time"
)

// BuildFeedbackEmail generates an HTML-formatted email body for user feedback
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Validate inputs
	if fromAddr == "" {
		return "", fmt.Errorf("from address cannot be empty")
	}
	if toAddr == "" {
		return "", fmt.Errorf("to address cannot be empty")
	}
	if userName == "" {
		return "", fmt.Errorf("user name cannot be empty")
	}
	if subject == "" {
		return "", fmt.Errorf("subject cannot be empty")
	}
	if feedbackContent == "" {
		return "", fmt.Errorf("feedback content cannot be empty")
	}

	// Create HTML email template
	emailTemplate := `<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <style>
        body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; margin: 0; padding: 0; }
        .container { max-width: 600px; margin: 20px auto; padding: 0; }
        .header { background-color: #4CAF50; color: white; padding: 20px; text-align: center; }
        .header h1 { margin: 0; font-size: 24px; }
        .content { padding: 20px; background-color: #f9f9f9; }
        .field { margin-bottom: 15px; }
        .label { font-weight: bold; color: #555; margin-bottom: 5px; }
        .value { padding: 10px; background-color: white; border: 1px solid #ddd; border-radius: 4px; word-wrap: break-word; }
        .footer { text-align: center; padding: 20px; color: #888; font-size: 12px; background-color: #f1f1f1; }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            <h1>User Feedback Received</h1>
        </div>
        <div class="content">
            <div class="field">
                <div class="label">Username:</div>
                <div class="value">{{.UserName}}</div>
            </div>
            <div class="field">
                <div class="label">Subject:</div>
                <div class="value">{{.Subject}}</div>
            </div>
            <div class="field">
                <div class="label">Feedback Content:</div>
                <div class="value">{{.FeedbackContent}}</div>
            </div>
            <div class="field">
                <div class="label">Submitted At:</div>
                <div class="value">{{.Timestamp}}</div>
            </div>
        </div>
        <div class="footer">
            <p>This is an automated feedback notification from the customer support system.</p>
            <p>Please do not reply to this email.</p>
        </div>
    </div>
</body>
</html>`

	// Prepare template data
	data := struct {
		UserName        string
		Subject         string
		FeedbackContent string
		Timestamp       string
	}{
		UserName:        userName,
		Subject:         subject,
		FeedbackContent: feedbackContent,
		Timestamp:       time.Now().Format("2006-01-02 15:04:05"),
	}

	// Parse and execute template
	tmpl, err := template.New("email").Parse(emailTemplate)
	if err != nil {
		return "", fmt.Errorf("failed to parse email template: %w", err)
	}

	var bodyBuffer bytes.Buffer
	err = tmpl.Execute(&bodyBuffer, data)
	if err != nil {
		return "", fmt.Errorf("failed to execute email template: %w", err)
	}

	// Build email headers with proper MIME format
	var emailBuilder strings.Builder
	emailBuilder.WriteString("From: " + fromAddr + "\r\n")
	emailBuilder.WriteString("To: " + toAddr + "\r\n")
	emailBuilder.WriteString("Subject: User Feedback: " + subject + "\r\n")
	emailBuilder.WriteString("MIME-Version: 1.0\r\n")
	emailBuilder.WriteString("Content-Type: text/html; charset=UTF-8\r\n")
	emailBuilder.WriteString("Content-Transfer-Encoding: quoted-printable\r\n")
	emailBuilder.WriteString("\r\n")
	emailBuilder.WriteString(bodyBuffer.String())

	return emailBuilder.String(), nil
}

// SendFeedbackEmail sends the feedback email using SMTP
func SendFeedbackEmail(smtpAddr string, auth smtp.Auth, fromAddr string, toAddr string, userName string, subject string, feedbackContent string) error {
	emailBody, err := BuildFeedbackEmail(fromAddr, toAddr, userName, subject, feedbackContent)
	if err != nil {
		return err
	}

	err = smtp.SendMail(smtpAddr, auth, fromAddr, []string{toAddr}, []byte(emailBody))
	if err != nil {
		return fmt.Errorf("failed to send email: %w", err)
	}

	return nil
}

