// BuildFeedbackEmail generates an HTML-formatted email body for user feedback
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Validate input parameters
	if strings.TrimSpace(fromAddr) == "" {
		return "", errors.New("from address cannot be empty")
	}
	if strings.TrimSpace(toAddr) == "" {
		return "", errors.New("to address cannot be empty")
	}
	if strings.TrimSpace(userName) == "" {
		return "", errors.New("username cannot be empty")
	}
	if strings.TrimSpace(subject) == "" {
		return "", errors.New("feedback subject cannot be empty")
	}
	if strings.TrimSpace(feedbackContent) == "" {
		return "", errors.New("feedback content cannot be empty")
	}

	// Define email template
	emailTemplate := `<!DOCTYPE html>
<html>
<head>
    <meta http-equiv="Content-Type" content="text/html; charset=UTF-8">
    <meta charset="UTF-8">
    <style>
        body {
            font-family: Arial, sans-serif;
            line-height: 1.6;
            color: #333;
            max-width: 600px;
            margin: 0 auto;
            padding: 20px;
        }
        .header {
            background-color: #4CAF50;
            color: white;
            padding: 20px;
            text-align: center;
            border-radius: 5px 5px 0 0;
