            border-top: none;
            border-radius: 0 0 5px 5px;
        }
        .field {
            margin-bottom: 15px;
        }
        .label {
            font-weight: bold;
            color: #555;
        }
        .value {
            background-color: white;
            padding: 10px;
            border: 1px solid #ddd;
            border-radius: 3px;
            margin-top: 5px;
        }
        .footer {
            text-align: center;
            margin-top: 20px;
            color: #888;
            font-size: 12px;
        }
    </style>
</head>
<body>
    <div class="header">
        <h1>📧 User Feedback Submission</h1>
    </div>
    <div class="content">
        <div class="field">
            <div class="label">From:</div>
            <div class="value">{{.FromAddr}}</div>
        </div>
        <div class="field">
            <div class="label">To:</div>
            <div class="value">{{.ToAddr}}</div>
        </div>
        <div class="field">
            <div class="label">Username:</div>
            <div class="value">{{.UserName}}</div>
        </div>
        <div class="field">
            <div class="label">Subject:</div>
            <div class="value">{{.Subject}}</div>
        </div>
        <div class="field">
            <div class="label">Feedback Content:</div>
            <div class="value">{{.FeedbackContent}}</div>
        </div>
    </div>
    <div class="footer">
        <p>This is an automated feedback notification from the customer support system.</p>
    </div>
</body>
</html>`

	// Parse template
	tmpl, err := template.New("feedbackEmail").Parse(emailTemplate)
	if err != nil {
		return "", fmt.Errorf("failed to parse email template: %w", err)
	}

	// Prepare template data
	data := struct {
		FromAddr        string
		ToAddr          string
		UserName        string
		Subject         string
		FeedbackContent string
	}{
		FromAddr:        fromAddr,
		ToAddr:          toAddr,
		UserName:        userName,
		Subject:         subject,
		FeedbackContent: feedbackContent,
	}

	// Execute template
	var buf bytes.Buffer
	err = tmpl.Execute(&buf, data)
	if err != nil {
		return "", fmt.Errorf("failed to execute email template: %w", err)
	}

	return buf.String(), nil
}

// SendFeedbackEmail sends the feedback email using SMTP
func SendFeedbackEmail(fromAddr, toAddr, smtpHost, smtpUser, smtpPass, userName, subject, feedbackContent string) error {
	// Build email body
	emailBody, err := BuildFeedbackEmail(fromAddr, toAddr, userName, subject, feedbackContent)
	if err != nil {
		return fmt.Errorf("failed to build email: %w", err)
	}

	// Create email message
	msg := []byte("From: " + fromAddr + "\r\n" +
		"To: " + toAddr + "\r\n" +
		"Subject: User Feedback: " + subject + "\r\n" +
		"MIME-Version: 1.0\r\n" +
		"Content-Type: text/html; charset=UTF-8\r\n" +
		"\r\n" +
		emailBody + "\r\n")

	// Authenticate with SMTP server
	auth := smtp.PlainAuth("", smtpUser, smtpPass, smtpHost)

	// Send email
	err = smtp.SendMail(smtpHost+":587", auth, fromAddr, []string{toAddr}, msg)
	if err != nil {
		return fmt.Errorf("failed to send email: %w", err)
	}

	return nil
}

