package main

import (
	"bytes"
	"fmt"
	"html/template"
	"time"
)

// BuildFeedbackEmail generates an HTML-formatted email body for user feedback
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Validate inputs
	if fromAddr == "" {
		return "", fmt.Errorf("fromAddr cannot be empty")
	}
	if toAddr == "" {
		return "", fmt.Errorf("toAddr cannot be empty")
	}
	if userName == "" {
		return "", fmt.Errorf("userName cannot be empty")
	}
	if subject == "" {
		return "", fmt.Errorf("subject cannot be empty")
	}
	if feedbackContent == "" {
		return "", fmt.Errorf("feedbackContent cannot be empty")
	}

	// Create email template
	emailTemplate := `<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <style>
        body {
            font-family: Arial, sans-serif;
            line-height: 1.6;
            color: #333;
            max-width: 600px;
            margin: 0 auto;
            padding: 20px;
        }
        .header {
            background-color: #4CAF50;
            color: white;
            padding: 20px;
            text-align: center;
            border-radius: 5px 5px 0 0;
        }
        .content {
            background-color: #f9f9f9;
            padding: 20px;
            border: 1px solid #ddd;
            border-radius: 0 0 5px 5px;
        }
        .field {
            margin-bottom: 15px;
        }
        .label {
            font-weight: bold;
            color: #555;
        }
        .value {
            background-color: white;
            padding: 10px;
            border: 1px solid #ddd;
            border-radius: 3px;
            margin-top: 5px;
        }
        .footer {
            margin-top: 20px;
            font-size: 12px;
            color: #888;
            text-align: center;
        }
    </style>
</head>
<body>
    <div class="header">
        <h1>User Feedback Report</h1>
    </div>
    <div class="content">
        <div class="field">
            <div class="label">From:</div>
            <div class="value">{{.FromAddr}}</div>
        </div>
        <div class="field">
            <div class="label">To:</div>
            <div class="value">{{.ToAddr}}</div>
        </div>
        <div class="field">
            <div class="label">User Name:</div>
            <div class="value">{{.UserName}}</div>
        </div>
        <div class="field">
            <div class="label">Subject:</div>
            <div class="value">{{.Subject}}</div>
        </div>
        <div class="field">
            <div class="label">Feedback Content:</div>
            <div class="value">{{.FeedbackContent}}</div>
        </div>
        <div class="field">
            <div class="label">Timestamp:</div>
            <div class="value">{{.Timestamp}}</div>
        </div>
    </div>
    <div class="footer">
        <p>This is an automated feedback report generated by the system.</p>
    </div>
</body>
</html>`

	// Create template
	tmpl, err := template.New("email").Parse(emailTemplate)
	if err != nil {
		return "", fmt.Errorf("failed to parse email template: %w", err)
	}

	// Prepare template data
	data := struct {
		FromAddr        string
		ToAddr          string
		UserName        string
		Subject         string
		FeedbackContent string
		Timestamp       string
	}{
		FromAddr:        fromAddr,
		ToAddr:          toAddr,
		UserName:        userName,
		Subject:         subject,
		FeedbackContent: feedbackContent,
		Timestamp:       time.Now().Format("2006-01-02 15:04:05"),
	}

	// Execute template
	var buf bytes.Buffer
	err = tmpl.Execute(&buf, data)
	if err != nil {
		return "", fmt.Errorf("failed to execute email template: %w", err)
	}

	return buf.String(), nil
}

func main() {
	// Example usage
	fromAddr := "feedback@example.com"
	toAddr := "support@example.com"
	userName := "John Doe"
	subject := "Feature Request: Dark Mode"
	feedbackContent := "I would love to see a dark mode option in the application. It would be easier on the eyes during night time usage."

	emailBody, err := BuildFeedbackEmail(fromAddr, toAddr, userName, subject, feedbackContent)
	if err != nil {
		fmt.Printf("Error building email: %v\n", err)
		return
	}

	fmt.Println("Email body generated successfully!")
	fmt.Println("Content Type: text/html; charset=UTF-8")
	fmt.Println("Email body length:", len(emailBody))
	fmt.Println("\n--- Email Preview (first 500 chars) ---")
	if len(emailBody) > 500 {
		fmt.Println(emailBody[:500] + "...")
	} else {
		fmt.Println(emailBody)
	}
}

