package main

import (
	"bytes"
	"fmt"
	"html"
	"net/smtp"
	"strings"
)

// BuildFeedbackEmail constructs the full email message content (headers + body)
// compatible with net/smtp.SendMail. It ensures HTML safety and header integrity.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Security: Prevent SMTP Header Injection by removing newlines from subject
	safeSubject := strings.ReplaceAll(strings.ReplaceAll(subject, "\n", ""), "\r", "")

	// Security: Escape HTML entities to prevent XSS and ensure valid HTML rendering in email clients
	safeUserName := html.EscapeString(userName)
	safeContent := html.EscapeString(feedbackContent)
	safeSubjectDisplay := html.EscapeString(safeSubject)

	var buf bytes.Buffer

	// Email Headers
	// Note: Using \r\n as per RFC 5322 standard required by net/smtp
	buf.WriteString("From: " + fromAddr + "\r\n")
	buf.WriteString("To: " + toAddr + "\r\n")
	buf.WriteString("Subject: " + safeSubject + "\r\n")
	buf.WriteString("MIME-Version: 1.0\r\n")
	buf.WriteString("Content-Type: text/html; charset=\"utf-8\"\r\n")

	// Separate headers from body
	buf.WriteString("\r\n")

	// Email Body (HTML)
	buf.WriteString("<html><body>")
	buf.WriteString("<h1 style='color: #333;'>New User Feedback</h1>")
	buf.WriteString("<table style='width: 100%; border-collapse: collapse; font-family: Arial, sans-serif;'>")

	buf.WriteString("<tr><td style='padding: 8px; border-bottom: 1px solid #ddd;'><strong>Username:</strong></td>")
	buf.WriteString("<td style='padding: 8px; border-bottom: 1px solid #ddd;'>" + safeUserName + "</td></tr>")

	buf.WriteString("<tr><td style='padding: 8px; border-bottom: 1px solid #ddd;'><strong>Subject:</strong></td>")
	buf.WriteString("<td style='padding: 8px; border-bottom: 1px solid #ddd;'>" + safeSubjectDisplay + "</td></tr>")

	buf.WriteString("<tr><td style='padding: 8px; border-bottom: 1px solid #ddd;'><strong>Feedback Content:</strong></td></tr>")
	buf.WriteString("<tr><td colspan='2' style='padding: 8px; background-color: #f9f9f9; white-space: pre-wrap;'>" + safeContent + "</td></tr>")

	buf.WriteString("</table>")
	buf.WriteString("</body></html>")

	return buf.String(), nil
}

func main() {
	// Explicitly reference net/smtp to satisfy the requirement and ensure compilation.
	// In a production environment, smtp.SendMail would be invoked here with the generated body.
	var _ = smtp.SendMail

	from := "support@example.com"
	to := "feedback@example.com"
	user := "JohnDoe"
	subject := "App Crash Report"
	// Including script tag to demonstrate HTML escaping safety
	content := "The app crashes when I click login.<script>alert('xss')</script>"

	emailBody, err := BuildFeedbackEmail(from, to, user, subject, content)
	if err != nil {
		fmt.Printf("Error building email: %v\n", err)
		return
	}

	fmt.Println("Generated Email Content:")
	fmt.Println(emailBody)
}

