// htmlEscape escapes HTML special characters and removes event handlers to prevent XSS attacks
func htmlEscape(s string) string {
	// First escape HTML entities using standard library
	s = html.EscapeString(s)

	// Remove any potential event handler patterns (onclick, onerror, onload, etc.)
	eventHandlerPattern := regexp.MustCompile(`(?i)on\w+\s*=`)
	s = eventHandlerPattern.ReplaceAllString(s, "")

	// Additional manual escaping for safety
	s = strings.ReplaceAll(s, "&", "&amp;")
	s = strings.ReplaceAll(s, "<", "&lt;")
	s = strings.ReplaceAll(s, ">", "&gt;")
	s = strings.ReplaceAll(s, "\"", "&quot;")
	s = strings.ReplaceAll(s, "'", "&#39;")

	return s
}

// SendFeedbackEmail sends the feedback email using SMTP
func SendFeedbackEmail(smtpServer string, smtpPort int, username string, password string, fromAddr string, toAddr string, userName string, subject string, feedbackContent string) error {
	emailBody, err := BuildFeedbackEmail(fromAddr, toAddr, userName, subject, feedbackContent)
	if err != nil {
		return err
	}

	// Create email message with headers
	msg := fmt.Sprintf("From: %s\r\n"+
		"To: %s\r\n"+
		"Subject: User Feedback - %s\r\n"+
		"MIME-Version: 1.0\r\n"+
		"Content-Type: text/html; charset=UTF-8\r\n"+
		"\r\n"+
		"%s", fromAddr, toAddr, subject, emailBody)

	// Send email using smtp package
	auth := smtp.PlainAuth("", username, password, smtpServer)
	addr := fmt.Sprintf("%s:%d", smtpServer, smtpPort)

	err = smtp.SendMail(addr, auth, fromAddr, []string{toAddr}, []byte(msg))
	if err != nil {
		return err
	}

	return nil
}

